  const [error, setError] = useState(null);
  const [zoom, setZoom] = useState(false);
  const [animatedScore, setAnimatedScore] = useState(0);
  const [downloading, setDownloading] = useState(false);

  const claimId = `CLM-${Date.now()}`;

  /* ---------------- Fraud Score Animation ---------------- */
  useEffect(() => {
    if (result) {
      let start = 0;
      const end = result.fraud_confidence_score || 0;
      const duration = 1200;
      const stepTime = 20;
      const step = (end - start) / (duration / stepTime);

      const interval = setInterval(() => {
        start += step;
        if (start >= end) {
          start = end;
          clearInterval(interval);
        }
        setAnimatedScore(Math.round(start));
      }, stepTime);
    }
  }, [result]);

  /* ---------------- Helper Functions ---------------- */
  const riskLevel = (score) => {
    if (score <= 40) return "Low Risk";
    if (score <= 75) return "Medium Risk";
    return "High Risk";
  };

  const gaugeColor = (score) => {
    if (score <= 50) return "#16a34a";
    if (score <= 80) return "#f59e0b";
    return "#dc2626";
  };

  const verdictColor = (verdict) => {
    if (!verdict) return "#555";
    if (verdict.toLowerCase() === "fraud") return "#dc2626";
    if (verdict.toLowerCase() === "suspicious") return "#f59e0b";
    return "#16a34a";
  };

  /* ---------------- File Handling ---------------- */
  const handleFileChange = (e) => {
    setError(null);
    const selected = e.target.files[0];
    if (!selected) return;

    setFile(selected);
    setPreview(URL.createObjectURL(selected));
    setResult(null);
    setAnimatedScore(0);
  };

  const handleUpload = async () => {
    if (!file) return setError("Please select an image first.");

    const formData = new FormData();
    formData.append("file", file);

    setLoading(true);
    setResult(null);

    try {
      const response = await fetch("http://127.0.0.1:8000/api/audit", {
        method: "POST",
        body: formData,
      });

      if (!response.ok) throw new Error("Server error");

      const data = await response.json();
      setResult(data);
    } catch (err) {
      setError(err.message || "Something went wrong!");
    }

    setLoading(false);
  };

  const handleReset = () => {
    setFile(null);
    setPreview(null);
    setResult(null);
    setError(null);
    setZoom(false);
    setAnimatedScore(0);
    setDownloading(false);
  };

  /* ---------------- Download as HTML ---------------- */
  const downloadReport = () => {
    if (!result) return;
    setDownloading(true);

    const htmlContent = `
      <html>
        <head>
          <title>Audit Report - ${claimId}</title>
          <style>
            body { font-family: Arial, sans-serif; padding: 20px; background: #f3f6fb; color: #333; }
            h1, h2, h3 { color: #1e40af; }
            .meta { font-size: 14px; color: #555; margin-bottom: 20px; }
            .stats { display: flex; flex-wrap: wrap; gap: 20px; margin-bottom: 30px; }
            .statBox { flex: 1 1 180px; background: #f4f7fa; padding: 15px; border-radius: 8px; text-align: center; }
            .details { line-height: 1.6; }
            ul { padding-left: 20px; }
            pre { background: #f1f5f9; padding: 10px; border-radius: 6px; overflow-x: auto; }
            .green { color: #16a34a; font-weight: bold; }
            .yellow { color: #f59e0b; font-weight: bold; }
            .red { color: #dc2626; font-weight: bold; }
          </style>
        </head>
        <body>
          <h1>ClaimPilot AI Audit Report</h1>
          <p class="meta">Claim ID: <strong>${claimId}</strong><br/>Date: ${new Date().toLocaleString()}</p>

          <div class="stats">
            <div class="statBox">
              <h3>Total Estimate</h3>
              <p>PKR ${result.total_estimate_pkr}</p>
            </div>
            <div class="statBox">
              <h3>Fraud Score</h3>
              <p class="${
                result.fraud_confidence_score <= 50
                  ? "green"
                  : result.fraud_confidence_score <= 80
                  ? "yellow"
                  : "red"
              }">${result.fraud_confidence_score}%</p>
            </div>
            <div class="statBox">
              <h3>Verdict</h3>
              <p class="${
                result.verdict.toLowerCase() === "fraud"
                  ? "red"
                  : result.verdict.toLowerCase() === "suspicious"
                  ? "yellow"
                  : "green"
              }">${result.verdict}</p>
            </div>
            <div class="statBox">
              <h3>Damaged Parts</h3>
              <p>${result.damaged_parts?.length || 0}</p>
            </div>
          </div>

          <div class="details">
            <h2>Fraud Analysis</h2>
            <p>${result.fraud_analysis || "No fraud detected."}</p>

            <h2>Damaged Parts</h2>
            ${
              result.damaged_parts?.length
                ? `<ul>${result.damaged_parts
                    .map((part) => `<li>${part}</li>`)
                    .join("")}</ul>`
                : "<p>No parts detected.</p>"
            }

            <h2>Itemized Costs</h2>
            <pre>${JSON.stringify(result.itemized_costs, null, 2)}</pre>

            <h2>AI Confidence Explanation</h2>
            <p>Score is calculated using anomaly detection, metadata consistency checks, and cost deviation models.</p>
          </div>
        </body>
      </html>
    `;

    const blob = new Blob([htmlContent], { type: "text/html" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `audit_report_${claimId}.html`;
    a.click();
    URL.revokeObjectURL(url);

    setTimeout(() => setDownloading(false), 800);
  };

  /* ---------------- UI ---------------- */
  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <header style={styles.header}>
          <h1 style={styles.logo}>ClaimPilot AI</h1>
          <p style={styles.tagline}>
            Intelligent Vehicle Damage Assessment & Fraud Detection
          </p>
          <div style={styles.status}>
            <span style={styles.dot}></span> AI System Active
          </div>
        </header>

        {/* Upload Card */}
        <div
          style={styles.uploadCard}
          onDragOver={(e) => e.preventDefault()}
          onDrop={(e) => {
            e.preventDefault();
            handleFileChange({ target: { files: [e.dataTransfer.files[0]] } });
          }}
        >
          {preview && (
            <img
              src={preview}
              alt="preview"
              style={zoom ? styles.previewZoom : styles.preview}
              onClick={() => setZoom(!zoom)}
            />
          )}

          <label style={styles.uploadLabel}>
            {file ? file.name : "Click or Drag Image Here"}
            <input
              type="file"
              accept="image/*"
              style={{ display: "none" }}
              onChange={handleFileChange}
            />
          </label>

          <div style={styles.buttonRow}>
            <button
              onClick={handleUpload}
              disabled={loading}
              style={loading ? styles.disabledBtn : styles.primaryBtn}
            >
              {loading ? "Analyzing..." : "Run AI Audit"}
            </button>

            {file && (
              <button onClick={handleReset} style={styles.resetBtn}>
                Reset
              </button>
            )}
          </div>

          {error && <p style={styles.error}>{error}</p>}
        </div>

        {/* Result Section */}
        {result && (
          <div style={styles.resultCard}>
            <h2>Audit Summary</h2>
            <p style={styles.meta}>
              Claim ID: <strong>{claimId}</strong> |{" "}
              {new Date().toLocaleString()}
            </p>

            {/* Stats Grid */}
            <div style={styles.stats}>
              <div style={styles.statBox}>
                <p>Total Estimate</p>
                <h3>PKR {result.total_estimate_pkr}</h3>
              </div>

              <div style={styles.statBox}>
                <p>Fraud Score</p>
                <svg viewBox="0 0 36 36" style={styles.gauge}>
                  <path
                    stroke="#eee"
                    fill="none"
                    strokeWidth="2.8"
                    d="M18 2.0845
                       a 15.9155 15.9155 0 0 1 0 31.831
                       a 15.9155 15.9155 0 0 1 0 -31.831"
                  />
                  <path
                    stroke={gaugeColor(animatedScore)}
                    strokeDasharray={`${animatedScore}, 100`}
                    fill="none"
                    strokeWidth="2.8"
                    d="M18 2.0845
                       a 15.9155 15.9155 0 0 1 0 31.831
                       a 15.9155 15.9155 0 0 1 0 -31.831"
                    style={{ transition: "stroke-dasharray 1s ease" }}
                  />
                  <text x="18" y="20.5" style={styles.gaugeText}>
                    {animatedScore}%
                  </text>
                </svg>
                <p style={{ color: gaugeColor(animatedScore), fontWeight: 600 }}>
                  {riskLevel(animatedScore)}
                </p>
              </div>

              <div
                style={{
                  ...styles.statBox,
                  color: verdictColor(result.verdict),
                }}
              >
                <p>Verdict</p>
                <h3>{result.verdict}</h3>
              </div>

              <div style={styles.statBox}>
                <p>Damaged Parts</p>
                <h3>{result.damaged_parts?.length || 0}</h3>
              </div>

              {result.estimated_repair_time && (
                <div style={styles.statBox}>
                  <p>Repair Time</p>
                  <h3>{result.estimated_repair_time}</h3>
                </div>
              )}
            </div>

            {/* Details */}
            <div style={styles.details}>
              <h3>Fraud Analysis</h3>
              <p>{result.fraud_analysis || "No fraud detected."}</p>

              <h3>Damaged Parts</h3>
              {result.damaged_parts?.length ? (
                <ul>
                  {result.damaged_parts.map((part, i) => (
                    <li key={i} style={styles.partItem}>
                      {part}
                      <span style={styles.severity}>Moderate</span>
                    </li>
                  ))}
                </ul>
              ) : (
                <p>No parts detected.</p>
              )}

              <h3>Itemized Costs</h3>
              <pre style={styles.pre}>
                {JSON.stringify(result.itemized_costs, null, 2)}
              </pre>

              <h3>AI Confidence Explanation</h3>
              <p>
                Score is calculated using anomaly detection, metadata
                consistency checks, and cost deviation models.
              </p>

              <button
                onClick={downloadReport}
                style={styles.downloadBtn}
                disabled={downloading}
              >
                {downloading ? "Preparing Report..." : "Download Audit Report"}
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

